@startuml
skinparam UMLClassBoxStyle fillcolor: #f0f0f0
skinparam UMLInterfaceBoxStyle fillcolor: #f0f0f0
skinparam UMLActorBoxStyle fillcolor: #f0f0f0

interface UserRepository {
    findUserByEmail(email: String) : User
    findUserByName(user: String) : User
}

interface WineRepository {
    findWineByUser(user: String) : List<Wine>
}

interface WineEstateRepository {
    findWineByEstate(estate: String) : WineEstate
    findWineByOwner(owner: String) : List<WineEstate>
}

actor User {
    "User"
}

actor Wine {
    "Wine"
}

actor WineEstate {
    "WineEstate"
}

User ..|> UserRepository : "findUserByEmail"
User ..|> UserRepository : "findUserByName"

Wine ..|> WineRepository : "findWineByUser"

WineEstate ..|> WineEstateRepository : "findWineByEstate"
WineEstate ..|> WineEstateRepository : "findWineByOwner"

@enduml
